# solution.py
"""Team_Collaboration_Manager.

A thread-safe, in-memory collaboration backend that manages users, projects,
tasks, messaging, performance metrics, and reporting.

The public surface is intentionally explicit and defensive: every mutating
operation validates its inputs, raises a precise exception subclass on error,
and returns deep copies so that callers can never accidentally corrupt the
internal store.  All state mutation is guarded by a single re-entrant lock that
is shared by every sub-repository, which keeps composite operations atomic and
the entity-id sequence globally unique even under heavy concurrency.

Standard library only, ASCII only.
"""

import copy
import csv
import io
import threading
from dataclasses import dataclass, field
from datetime import datetime
from enum import Enum
from typing import Callable, Dict, List, Optional


# ---------------------------------------------------------------------------
# Enumerations
# ---------------------------------------------------------------------------
class UserRole(Enum):
    """Role assigned to a registered user."""

    MEMBER = "member"
    ADMIN = "admin"
    GUEST = "guest"


class TaskStatus(Enum):
    """Lifecycle status of a task."""

    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class ReportFormat(Enum):
    """Supported export formats for generated reports."""

    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    """Categories of generated reports."""

    PROJECT_PROGRESS = "project_progress"
    TEAM_PERFORMANCE = "team_performance"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for every error raised by the manager."""


class ValidationError(TeamCollaborationError):
    """Raised when an argument fails a validation rule."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not permitted to perform an action."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint is violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an operation conflicts with existing state."""


# ---------------------------------------------------------------------------
# Data models
# ---------------------------------------------------------------------------
@dataclass
class User:
    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime


@dataclass
class Project:
    id: int
    name: str
    description: str
    start_date: datetime
    end_date: datetime
    owner_id: int
    created_at: datetime


@dataclass
class Task:
    id: int
    project_id: int
    title: str
    status: TaskStatus
    assignee_id: Optional[int] = None
    deadline: Optional[datetime] = None
    started_at: Optional[datetime] = None
    completed_at: Optional[datetime] = None
    created_at: Optional[datetime] = None


@dataclass
class Attachment:
    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime


@dataclass
class Message:
    id: int
    author_id: int
    body: str
    project_id: Optional[int] = None
    task_id: Optional[int] = None
    parent_id: Optional[int] = None
    attachments: List[Attachment] = field(default_factory=list)
    created_at: Optional[datetime] = None
    edited_at: Optional[datetime] = None


@dataclass
class Rating:
    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: str
    task_id: Optional[int]
    created_at: datetime


# ---------------------------------------------------------------------------
# Repositories (thin data holders that all share one lock)
# ---------------------------------------------------------------------------
class _BaseRepository:
    """Common base giving every repository the shared lock."""

    def __init__(self, lock):
        self._lock = lock


class _UserRepository(_BaseRepository):
    def __init__(self, lock):
        super().__init__(lock)
        self._by_id = {}
        self._by_username = {}
        self._by_email = {}


class _ProjectRepository(_BaseRepository):
    def __init__(self, lock):
        super().__init__(lock)
        self._by_id = {}


class _TaskRepository(_BaseRepository):
    def __init__(self, lock):
        super().__init__(lock)
        self._by_id = {}
        self._by_project = {}
        self._by_assignee = {}


class _MessageRepository(_BaseRepository):
    def __init__(self, lock):
        super().__init__(lock)
        self._by_id = {}
        self._by_project = {}
        self._by_task = {}


class _PerformanceRepository(_BaseRepository):
    def __init__(self, lock):
        super().__init__(lock)
        self._by_id = {}
        self._by_ratee = {}


class _ReportRepository(_BaseRepository):
    """Stateless service object; only needs the shared lock."""


# ---------------------------------------------------------------------------
# Helpers
# ---------------------------------------------------------------------------
def _stringify(value):
    if isinstance(value, datetime):
        return value.isoformat()
    return str(value)


def _build_pdf(lines):
    """Assemble a minimal but structurally valid single-page PDF document."""

    content_parts = ["BT", "/F1 12 Tf", "72 720 Td"]
    first = True
    for line in lines:
        safe = (
            str(line)
            .replace("\\", "\\\\")
            .replace("(", "\\(")
            .replace(")", "\\)")
        )
        if not first:
            content_parts.append("0 -16 Td")
        content_parts.append("({0}) Tj".format(safe))
        first = False
    content_parts.append("ET")
    content = "\n".join(content_parts).encode("latin-1", "replace")

    objects = [
        b"<< /Type /Catalog /Pages 2 0 R >>",
        b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
        b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
        b"/Contents 4 0 R /Resources << /Font << /F1 5 0 R >> >> >>",
        b"<< /Length " + str(len(content)).encode("ascii") + b" >>\nstream\n"
        + content + b"\nendstream",
        b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
    ]

    pdf = bytearray(b"%PDF-1.4\n")
    offsets = []
    for index, body in enumerate(objects, start=1):
        offsets.append(len(pdf))
        pdf += str(index).encode("ascii") + b" 0 obj\n" + body + b"\nendobj\n"

    xref_position = len(pdf)
    total = len(objects) + 1
    pdf += b"xref\n0 " + str(total).encode("ascii") + b"\n"
    pdf += b"0000000000 65535 f \n"
    for offset in offsets:
        pdf += "{0:010d} 00000 n \n".format(offset).encode("ascii")
    pdf += b"trailer\n<< /Size " + str(total).encode("ascii")
    pdf += b" /Root 1 0 R >>\nstartxref\n"
    pdf += str(xref_position).encode("ascii") + b"\n%%EOF"
    return bytes(pdf)


# ---------------------------------------------------------------------------
# Manager
# ---------------------------------------------------------------------------
class TeamCollaborationManager:
    """Coordinates all collaboration entities behind a single shared lock."""

    def __init__(self, now: Optional[Callable[[], datetime]] = None):
        self._now = now if now is not None else datetime.now
        self._lock = threading.RLock()
        self._id_counter = 0

        self.users = _UserRepository(self._lock)
        self.projects = _ProjectRepository(self._lock)
        self.tasks = _TaskRepository(self._lock)
        self.messages = _MessageRepository(self._lock)
        self.performance = _PerformanceRepository(self._lock)
        self.reports = _ReportRepository(self._lock)

    # -- internal utilities -------------------------------------------------
    def _next_id(self):
        with self._lock:
            self._id_counter += 1
            return self._id_counter

    @staticmethod
    def _clone(value):
        return copy.deepcopy(value)

    def _require_user(self, user_id):
        user = self.users._by_id.get(user_id)
        if user is None:
            raise NotFoundError("User {0} not found".format(user_id))
        return user

    def _require_project(self, project_id):
        project = self.projects._by_id.get(project_id)
        if project is None:
            raise NotFoundError("Project {0} not found".format(project_id))
        return project

    def _require_task(self, task_id):
        task = self.tasks._by_id.get(task_id)
        if task is None:
            raise NotFoundError("Task {0} not found".format(task_id))
        return task

    def _require_message(self, message_id):
        message = self.messages._by_id.get(message_id)
        if message is None:
            raise NotFoundError("Message {0} not found".format(message_id))
        return message

    @staticmethod
    def _validate_email(email):
        if not isinstance(email, str) or not email.strip() or "@" not in email:
            raise ValidationError("Invalid email address")

    # -- assignee index helpers --------------------------------------------
    def _index_assignee(self, user_id, task_id):
        if user_id is None:
            return
        self.tasks._by_assignee.setdefault(user_id, set()).add(task_id)

    def _deindex_assignee(self, user_id, task_id):
        if user_id is None:
            return
        bucket = self.tasks._by_assignee.get(user_id)
        if bucket is not None:
            bucket.discard(task_id)

    def _set_task_assignee(self, task, new_assignee_id):
        if task.assignee_id == new_assignee_id:
            return
        self._deindex_assignee(task.assignee_id, task.id)
        task.assignee_id = new_assignee_id
        self._index_assignee(new_assignee_id, task.id)

    # =====================================================================
    # User management
    # =====================================================================
    def register_user(self, username, email, role=UserRole.MEMBER):
        with self._lock:
            if not isinstance(username, str) or not username.strip():
                raise ValidationError("Username must be a non-empty string")
            self._validate_email(email)
            if not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")

            username = username.strip()
            email = email.strip()
            username_key = username
            email_key = email.lower()

            if username_key in self.users._by_username:
                raise DuplicateError("Username already in use")
            if email_key in self.users._by_email:
                raise DuplicateError("Email already in use")

            user = User(
                id=self._next_id(),
                username=username,
                email=email,
                role=role,
                created_at=self._now(),
            )
            self.users._by_id[user.id] = user
            self.users._by_username[username_key] = user.id
            self.users._by_email[email_key] = user.id
            return self._clone(user)

    def get_user(self, user_id):
        with self._lock:
            return self._clone(self._require_user(user_id))

    def list_users(self):
        with self._lock:
            return [
                self._clone(self.users._by_id[uid])
                for uid in sorted(self.users._by_id)
            ]

    def update_user(self, user_id, username=None, email=None, role=None):
        with self._lock:
            user = self._require_user(user_id)

            if username is not None:
                if not isinstance(username, str) or not username.strip():
                    raise ValidationError("Username must be a non-empty string")
                new_key = username.strip()
                existing = self.users._by_username.get(new_key)
                if existing is not None and existing != user_id:
                    raise DuplicateError("Username already in use")

            if email is not None:
                self._validate_email(email)
                new_email_key = email.strip().lower()
                existing = self.users._by_email.get(new_email_key)
                if existing is not None and existing != user_id:
                    raise DuplicateError("Email already in use")

            if role is not None and not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")

            if username is not None:
                new_key = username.strip()
                del self.users._by_username[user.username]
                user.username = new_key
                self.users._by_username[new_key] = user_id

            if email is not None:
                new_email = email.strip()
                del self.users._by_email[user.email.lower()]
                user.email = new_email
                self.users._by_email[new_email.lower()] = user_id

            if role is not None:
                user.role = role

            return self._clone(user)

    def delete_user(self, user_id):
        with self._lock:
            user = self._require_user(user_id)

            for project in self.projects._by_id.values():
                if project.owner_id == user_id:
                    raise ConflictError("User owns a project and cannot be deleted")

            for task_id in self.tasks._by_assignee.get(user_id, set()):
                task = self.tasks._by_id.get(task_id)
                if task is not None and task.status != TaskStatus.COMPLETED:
                    raise ConflictError(
                        "User has an open task and cannot be deleted"
                    )

            del self.users._by_id[user_id]
            self.users._by_username.pop(user.username, None)
            self.users._by_email.pop(user.email.lower(), None)
            self.tasks._by_assignee.pop(user_id, None)

    # =====================================================================
    # Project management
    # =====================================================================
    def create_project(self, name, start_date, end_date, owner_id, description=""):
        with self._lock:
            if not isinstance(name, str) or not name.strip():
                raise ValidationError("Project name must be a non-empty string")
            self._require_user(owner_id)
            if end_date < start_date:
                raise ValidationError("end_date cannot precede start_date")

            project = Project(
                id=self._next_id(),
                name=name.strip(),
                description=description or "",
                start_date=start_date,
                end_date=end_date,
                owner_id=owner_id,
                created_at=self._now(),
            )
            self.projects._by_id[project.id] = project
            self.tasks._by_project.setdefault(project.id, set())
            self.messages._by_project.setdefault(project.id, set())
            return self._clone(project)

    def get_project(self, project_id):
        with self._lock:
            return self._clone(self._require_project(project_id))

    def list_projects(self):
        with self._lock:
            return [
                self._clone(self.projects._by_id[pid])
                for pid in sorted(self.projects._by_id)
            ]

    def update_project(
        self, project_id, name=None, description=None, start_date=None, end_date=None
    ):
        with self._lock:
            project = self._require_project(project_id)

            if name is not None and (not isinstance(name, str) or not name.strip()):
                raise ValidationError("Project name must be a non-empty string")

            effective_start = start_date if start_date is not None else project.start_date
            effective_end = end_date if end_date is not None else project.end_date
            if effective_end < effective_start:
                raise ValidationError("end_date cannot precede start_date")

            if name is not None:
                project.name = name.strip()
            if description is not None:
                project.description = description
            if start_date is not None:
                project.start_date = start_date
            if end_date is not None:
                project.end_date = end_date
            return self._clone(project)

    def delete_project(self, project_id):
        with self._lock:
            self._require_project(project_id)

            task_ids = list(self.tasks._by_project.get(project_id, set()))
            for task_id in task_ids:
                task = self.tasks._by_id.pop(task_id, None)
                if task is not None:
                    self._deindex_assignee(task.assignee_id, task_id)
                    self._purge_task_messages(task_id)
            self.tasks._by_project.pop(project_id, None)

            message_ids = list(self.messages._by_project.get(project_id, set()))
            for message_id in message_ids:
                self.messages._by_id.pop(message_id, None)
            self.messages._by_project.pop(project_id, None)

            del self.projects._by_id[project_id]

    def _purge_task_messages(self, task_id):
        message_ids = list(self.messages._by_task.get(task_id, set()))
        for message_id in message_ids:
            self.messages._by_id.pop(message_id, None)
        self.messages._by_task.pop(task_id, None)

    # =====================================================================
    # Task management
    # =====================================================================
    def create_task(self, project_id, title, assignee_id=None, deadline=None):
        with self._lock:
            project = self._require_project(project_id)
            if not isinstance(title, str) or not title.strip():
                raise ValidationError("Task title must be a non-empty string")
            if assignee_id is not None:
                self._require_user(assignee_id)
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("deadline cannot precede project start")

            task = Task(
                id=self._next_id(),
                project_id=project_id,
                title=title.strip(),
                status=TaskStatus.NOT_STARTED,
                assignee_id=assignee_id,
                deadline=deadline,
                started_at=None,
                completed_at=None,
                created_at=self._now(),
            )
            self.tasks._by_id[task.id] = task
            self.tasks._by_project.setdefault(project_id, set()).add(task.id)
            self._index_assignee(assignee_id, task.id)
            return self._clone(task)

    def get_task(self, task_id):
        with self._lock:
            return self._clone(self._require_task(task_id))

    def list_tasks_by_project(self, project_id):
        with self._lock:
            self._require_project(project_id)
            ids = self.tasks._by_project.get(project_id, set())
            return [self._clone(self.tasks._by_id[tid]) for tid in sorted(ids)]

    def list_tasks_by_assignee(self, user_id):
        with self._lock:
            self._require_user(user_id)
            ids = self.tasks._by_assignee.get(user_id, set())
            return [self._clone(self.tasks._by_id[tid]) for tid in sorted(ids)]

    def assign_task(self, task_id, assignee_id):
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(assignee_id)
            self._set_task_assignee(task, assignee_id)
            return self._clone(task)

    def reassign_task(self, task_id, new_assignee_id):
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(new_assignee_id)
            self._set_task_assignee(task, new_assignee_id)
            return self._clone(task)

    def unassign_task(self, task_id):
        with self._lock:
            task = self._require_task(task_id)
            self._set_task_assignee(task, None)
            return self._clone(task)

    def set_deadline(self, task_id, deadline):
        with self._lock:
            task = self._require_task(task_id)
            if deadline is not None:
                project = self.projects._by_id.get(task.project_id)
                if project is not None and deadline < project.start_date:
                    raise ValidationError("deadline cannot precede project start")
            task.deadline = deadline
            return self._clone(task)

    def update_status(self, task_id, status):
        with self._lock:
            task = self._require_task(task_id)
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus")

            now = self._now()
            if status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            elif status == TaskStatus.NOT_STARTED:
                task.started_at = None
                task.completed_at = None

            task.status = status
            return self._clone(task)

    # =====================================================================
    # Messaging
    # =====================================================================
    def post_message(
        self,
        author_id,
        body,
        project_id=None,
        task_id=None,
        parent_id=None,
        attachments=None,
    ):
        with self._lock:
            self._require_user(author_id)

            if (project_id is None) == (task_id is None):
                raise ValidationError(
                    "Exactly one of project_id or task_id is required"
                )
            if project_id is not None:
                self._require_project(project_id)
            if task_id is not None:
                self._require_task(task_id)

            has_body = isinstance(body, str) and body.strip() != ""
            has_attachments = bool(attachments)
            if not has_body and not has_attachments:
                raise ValidationError("Message requires a body or an attachment")

            if parent_id is not None:
                self._require_message(parent_id)

            now = self._now()
            built_attachments = []
            for filename, data in attachments or []:
                built_attachments.append(
                    Attachment(
                        filename=filename,
                        size=len(data),
                        uploaded_by=author_id,
                        uploaded_at=now,
                    )
                )

            message = Message(
                id=self._next_id(),
                author_id=author_id,
                body=body if body is not None else "",
                project_id=project_id,
                task_id=task_id,
                parent_id=parent_id,
                attachments=built_attachments,
                created_at=now,
                edited_at=None,
            )
            self.messages._by_id[message.id] = message
            if project_id is not None:
                self.messages._by_project.setdefault(project_id, set()).add(message.id)
            if task_id is not None:
                self.messages._by_task.setdefault(task_id, set()).add(message.id)
            return self._clone(message)

    def edit_message(self, message_id, editor_id, new_body):
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != editor_id:
                raise AuthorizationError("Only the author may edit a message")
            if not isinstance(new_body, str) or not new_body.strip():
                raise ValidationError("Message body must be a non-empty string")
            message.body = new_body
            message.edited_at = self._now()
            return self._clone(message)

    def add_attachment(self, message_id, uploader_id, filename, data):
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != uploader_id:
                raise AuthorizationError("Only the author may attach files")
            if not isinstance(filename, str) or not filename.strip():
                raise ValidationError("filename must be a non-empty string")
            message.attachments.append(
                Attachment(
                    filename=filename,
                    size=len(data),
                    uploaded_by=uploader_id,
                    uploaded_at=self._now(),
                )
            )
            return self._clone(message)

    def list_messages_by_project(self, project_id):
        with self._lock:
            self._require_project(project_id)
            ids = self.messages._by_project.get(project_id, set())
            return [self._clone(self.messages._by_id[mid]) for mid in sorted(ids)]

    def list_messages_by_task(self, task_id):
        with self._lock:
            self._require_task(task_id)
            ids = self.messages._by_task.get(task_id, set())
            return [self._clone(self.messages._by_id[mid]) for mid in sorted(ids)]

    def delete_message(self, message_id, requester_id):
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != requester_id:
                raise AuthorizationError("Only the author may delete a message")
            if message.project_id is not None:
                bucket = self.messages._by_project.get(message.project_id)
                if bucket is not None:
                    bucket.discard(message_id)
            if message.task_id is not None:
                bucket = self.messages._by_task.get(message.task_id)
                if bucket is not None:
                    bucket.discard(message_id)
            del self.messages._by_id[message_id]

    # =====================================================================
    # Performance dashboard
    # =====================================================================
    def _tasks_for_user(self, user_id):
        ids = self.tasks._by_assignee.get(user_id, set())
        return [self.tasks._by_id[tid] for tid in ids if tid in self.tasks._by_id]

    @staticmethod
    def _completion_rate(tasks):
        if not tasks:
            return 0.0
        completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
        return completed / len(tasks)

    @staticmethod
    def _average_completion_time(tasks):
        durations = []
        for task in tasks:
            if (
                task.status == TaskStatus.COMPLETED
                and task.started_at is not None
                and task.completed_at is not None
            ):
                durations.append(
                    (task.completed_at - task.started_at).total_seconds()
                )
        if not durations:
            return None
        return sum(durations) / len(durations)

    def get_completion_rate(self, user_id):
        with self._lock:
            self._require_user(user_id)
            return self._completion_rate(self._tasks_for_user(user_id))

    def get_average_completion_time(self, user_id):
        with self._lock:
            self._require_user(user_id)
            return self._average_completion_time(self._tasks_for_user(user_id))

    def submit_rating(self, rater_id, ratee_id, score, feedback="", task_id=None):
        with self._lock:
            self._require_user(rater_id)
            self._require_user(ratee_id)
            if rater_id == ratee_id:
                raise ConflictError("A user cannot rate themselves")
            if not isinstance(score, int) or isinstance(score, bool):
                raise ValidationError("score must be an integer")
            if score < 1 or score > 5:
                raise ValidationError("score must be between 1 and 5")
            if task_id is not None:
                self._require_task(task_id)

            rating = Rating(
                id=self._next_id(),
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                feedback=feedback or "",
                task_id=task_id,
                created_at=self._now(),
            )
            self.performance._by_id[rating.id] = rating
            self.performance._by_ratee.setdefault(ratee_id, []).append(rating.id)
            return self._clone(rating)

    def _ratings_for_user(self, user_id):
        ids = self.performance._by_ratee.get(user_id, [])
        return [self.performance._by_id[rid] for rid in ids]

    def get_ratings_summary(self, user_id):
        with self._lock:
            self._require_user(user_id)
            ratings = self._ratings_for_user(user_id)
            count = len(ratings)
            average = (
                sum(r.score for r in ratings) / count if count else 0.0
            )
            return {
                "user_id": user_id,
                "count": count,
                "average": average,
                "ratings": [self._clone(r) for r in ratings],
            }

    def get_user_dashboard(self, user_id):
        with self._lock:
            self._require_user(user_id)
            tasks = self._tasks_for_user(user_id)
            ratings = self._ratings_for_user(user_id)
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count
                if rating_count
                else 0.0
            )
            return {
                "user_id": user_id,
                "total_tasks": len(tasks),
                "completed_tasks": sum(
                    1 for t in tasks if t.status == TaskStatus.COMPLETED
                ),
                "in_progress_tasks": sum(
                    1 for t in tasks if t.status == TaskStatus.IN_PROGRESS
                ),
                "not_started_tasks": sum(
                    1 for t in tasks if t.status == TaskStatus.NOT_STARTED
                ),
                "completion_rate": self._completion_rate(tasks),
                "average_completion_time": self._average_completion_time(tasks),
                "rating_count": rating_count,
                "rating_average": rating_average,
            }

    # =====================================================================
    # Reports
    # =====================================================================
    def project_progress_report(self, project_id):
        with self._lock:
            self._require_project(project_id)
            task_ids = self.tasks._by_project.get(project_id, set())
            tasks = [self.tasks._by_id[tid] for tid in task_ids]
            now = self._now()

            status_counts = {status.value: 0 for status in TaskStatus}
            overdue = 0
            per_assignee = {}
            for task in tasks:
                status_counts[task.status.value] += 1
                if (
                    task.deadline is not None
                    and task.deadline < now
                    and task.status != TaskStatus.COMPLETED
                ):
                    overdue += 1
                if task.assignee_id is not None:
                    bucket = per_assignee.setdefault(
                        task.assignee_id,
                        {"total": 0, "completed": 0, "completion_rate": 0.0},
                    )
                    bucket["total"] += 1
                    if task.status == TaskStatus.COMPLETED:
                        bucket["completed"] += 1

            for bucket in per_assignee.values():
                if bucket["total"]:
                    bucket["completion_rate"] = bucket["completed"] / bucket["total"]

            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "total_tasks": len(tasks),
                "status_counts": status_counts,
                "completion_rate": self._completion_rate(tasks),
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def team_performance_report(self, project_id=None):
        with self._lock:
            if project_id is not None:
                self._require_project(project_id)
                task_ids = self.tasks._by_project.get(project_id, set())
                scope_tasks = [self.tasks._by_id[tid] for tid in task_ids]
            else:
                scope_tasks = list(self.tasks._by_id.values())

            by_user = {}
            for task in scope_tasks:
                if task.assignee_id is not None:
                    by_user.setdefault(task.assignee_id, []).append(task)

            rows = []
            for user_id in sorted(by_user):
                user_tasks = by_user[user_id]
                ratings = self._ratings_for_user(user_id)
                rating_count = len(ratings)
                rating_average = (
                    sum(r.score for r in ratings) / rating_count
                    if rating_count
                    else 0.0
                )
                rows.append(
                    {
                        "user_id": user_id,
                        "total_tasks": len(user_tasks),
                        "completed_tasks": sum(
                            1
                            for t in user_tasks
                            if t.status == TaskStatus.COMPLETED
                        ),
                        "completion_rate": self._completion_rate(user_tasks),
                        "average_completion_time": self._average_completion_time(
                            user_tasks
                        ),
                        "rating_count": rating_count,
                        "rating_average": rating_average,
                    }
                )

            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "project_id": project_id,
                "rows": rows,
            }

    def individual_performance_report(self, user_id):
        with self._lock:
            self._require_user(user_id)
            tasks = sorted(self._tasks_for_user(user_id), key=lambda t: t.id)
            ratings = self._ratings_for_user(user_id)
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count
                if rating_count
                else 0.0
            )
            task_rows = [
                {
                    "task_id": t.id,
                    "title": t.title,
                    "status": t.status.value,
                    "project_id": t.project_id,
                    "deadline": t.deadline,
                }
                for t in tasks
            ]
            return {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
                "total_tasks": len(tasks),
                "completed_tasks": sum(
                    1 for t in tasks if t.status == TaskStatus.COMPLETED
                ),
                "completion_rate": self._completion_rate(tasks),
                "average_completion_time": self._average_completion_time(tasks),
                "rating_count": rating_count,
                "rating_average": rating_average,
                "tasks": task_rows,
            }

    def export_report(self, report, report_format):
        if not isinstance(report_format, ReportFormat):
            raise ValidationError("report_format must be a ReportFormat")
        if not isinstance(report, dict):
            raise ValidationError("report must be a dict")

        if report_format == ReportFormat.CSV:
            return self._export_csv(report)
        return self._export_pdf(report)

    @staticmethod
    def _export_csv(report):
        output = io.StringIO()
        writer = csv.writer(output)
        rows = report.get("rows")
        if isinstance(rows, list):
            if rows:
                header = list(rows[0].keys())
            else:
                header = [
                    key
                    for key, value in report.items()
                    if not isinstance(value, (dict, list))
                ] or ["report_type"]
            writer.writerow(header)
            for row in rows:
                writer.writerow([_stringify(row.get(key, "")) for key in header])
        else:
            items = list(report.items())
            writer.writerow([key for key, _ in items])
            writer.writerow([_stringify(value) for _, value in items])
        return output.getvalue()

    @staticmethod
    def _export_pdf(report):
        lines = ["Report Type: {0}".format(report.get("report_type", "report"))]
        for key, value in report.items():
            if key == "report_type":
                continue
            lines.append("{0}: {1}".format(key, _stringify(value)))
        return _build_pdf(lines)
